k10_fit <- k_means(num_clusters = 10) |>
  set_engine("stats") |>
  fit(~., data = college_df |>
        select_if(is.numeric) |>
        mutate(across(where(is.numeric), scale)))
college_k10 <- college_df |>
  mutate(cluster_num = extract_cluster_assignment(k10_fit) |>
           pull())
